--- 领取皮肤套装奖励
---@param suitId number 套装配置id
function LxHeroSkinHandler:HeroSkinSuitReceiveReq(suitId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroSkinSuitReceiveReq)
    proto.suitId = suitId
    SendMessage(LxProtoIds.HeroSkinSuitReceiveReq, proto)
end

--- 激活皮肤
---@param refId number 道具id
function LxHeroSkinHandler:HeroSkinActivationReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroSkinActivationReq)
    proto.refId = refId
    SendMessage(LxProtoIds.HeroSkinActivationReq, proto)
end

--- 穿戴皮肤
---@param heroId number 英雄id
---@param refId number 皮肤id
function LxHeroSkinHandler:HeroSkinSelectReq(heroId,refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroSkinSelectReq)
    proto.heroId = heroId
    proto.refId = refId
    SendMessage(LxProtoIds.HeroSkinSelectReq, proto)
end

