--- s2c

--- 领取皮肤套装奖励
function LxHeroSkinHandler:OnHeroSkinSuitReceiveResp(pb)
    --- 英雄皮肤套装信息
    ModuleCenter.HeroSkin:SetHeroSkinSuitObj(pb.suitObj)

    ---@type LxThingsInfo 获得的奖励
    local things = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.HeroSkinSuit, things)

    FireEvent(EventNames.REFRESH_HERO_ALLRP,{
        refreshWay = LxProtoIds.HeroSkinSuitReceiveResp,
    })
end

--- 激活皮肤
function LxHeroSkinHandler:OnHeroSkinActivationResp(pb)
    --- 道具id
    local refId = pb.refId
end

--- 皮肤变化
function LxHeroSkinHandler:OnHeroSkinChangeResp(pb)
    local heroSkinModule = ModuleCenter.HeroSkin

    --- 英雄皮肤变化信息
    heroSkinModule:SetHeroSkinObjs(pb.skins)

    --- 英雄皮肤图鉴变化信息
    heroSkinModule:SetHeroSkinBookInfo(pb.bookInfo)
end

--- 穿戴皮肤
function LxHeroSkinHandler:OnHeroSkinSelectResp(pb)
    --- pb.heroId:英雄id
    ---@type LxHeroObj
    local heroObj = ModuleCenter.Hero:GetHero(pb.heroId)
    if not heroObj then return end

    --- 皮肤id
    heroObj:SetHeroSkinId(pb.refId)
end

return LxHeroSkinHandler